import{_ as t,o,c as r,ae as i}from"./chunks/framework.B6gjLfeO.js";const y=JSON.parse('{"title":"Journeys Manager","description":"","frontmatter":{"title":"Journeys Manager","slug":"manage-journeys"},"headers":[],"relativePath":"marketer-hub/manage-journeys.md","filePath":"marketer-hub/manage-journeys.md"}'),a={name:"marketer-hub/manage-journeys.md"};function n(s,e,l,u,h,d){return o(),r("div",null,[...e[0]||(e[0]=[i('<h2 id="managing-journeys-app-banners" tabindex="-1">Managing Journeys App Banners <a class="header-anchor" href="#managing-journeys-app-banners" aria-label="Permalink to &quot;Managing Journeys App Banners&quot;">​</a></h2><p>The <a href="https://dashboard.branch.io/journeys/manager" target="_blank" rel="noreferrer">Journeys Manager</a> is your homepage for all of the personalized experiences you have created.</p><p>From the actions menu you can:</p><ul><li>Start</li><li>Schedule</li><li>Edit</li><li>Clone</li><li>Analyze</li><li>Archive</li></ul><h3 id="journey-status" tabindex="-1">Journey Status <a class="header-anchor" href="#journey-status" aria-label="Permalink to &quot;Journey Status&quot;">​</a></h3><p>A Journey can have one of five statuses:</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td>Draft</td><td>Not yet published but editable. If you delete a draft, <strong>it also deletes the corresponding creative</strong>.</td></tr><tr><td>Active</td><td>Live for your users and editable.</td></tr><tr><td>Stopped</td><td>Not live for your users but editable.</td></tr><tr><td>Archived</td><td>Not live for your users but editable.</td></tr><tr><td>Scheduled</td><td>Not live until set date/time but editable.</td></tr></tbody></table><h2 id="filter-view" tabindex="-1">Filter View <a class="header-anchor" href="#filter-view" aria-label="Permalink to &quot;Filter View&quot;">​</a></h2><p><strong>Filter View</strong> allows you to set specific filters to organize all of your Journeys in one place.</p><p>For any Journey, you can set/change its state, reorder its priority, edit or clone it, and analyze its performance. You can also adjust the filters to show Journeys by state, and you can sort by column.</p><h3 id="journey-quick-look" tabindex="-1">Journey Quick Look <a class="header-anchor" href="#journey-quick-look" aria-label="Permalink to &quot;Journey Quick Look&quot;">​</a></h3><p>To quickly preview the contents of a Journeys banner, simply hover on the corresponding row. An overlay appears that displays up to two previews of banners and up to two filters configured for a Journey.</p><p>You can also <strong>Add More Templates</strong> and/or <strong>Add Rules</strong> to the Journey from the Quick Look.</p><h2 id="journeys-versioning" tabindex="-1">Journeys Versioning <a class="header-anchor" href="#journeys-versioning" aria-label="Permalink to &quot;Journeys Versioning&quot;">​</a></h2><p>When you are editing a Journey (that is in any state <strong>except the draft state</strong>), you can save your changes in a way that updates the version number associated with that Journey.</p><p>By changing the version number as you are making edits to your Journey, you can keep track of different variations to that Journey and keep a historical log of any updates.</p><p>To use the versioning system:</p><ol><li><p>Click on the three dots in the row associated with the Journey you are interested in. This will open a menu of actions you can take.</p></li><li><p>Click on the <strong>Edit</strong> option to open details about the Journey that you can make changes to.</p></li><li><p>Make the edits that you need to make for this Journey, and then click the <strong>Save &amp; Continue</strong> button.</p></li><li><p>At this point, a popup will appear asking if you would like to increase the version number for the Journey you are working on.</p></li><li><p>To increase the version number of the Journey, click the <strong>Yes, proceed</strong> button.</p><ol><li>You also have the option to skip a version increase by clicking <strong>Proceed without version update</strong>.</li></ol></li><li><p>Once you&#39;ve increased the version number, you can also add a descriptive note to associate with that version.</p></li><li><p>Click <strong>Save</strong> to save your update note.</p></li><li><p>Continue through the <strong>Configure Creatives</strong> and <strong>Validate &amp; Test</strong> sections. When you are done, you will be brought back to the <strong>Manager</strong> tab.</p></li><li><p>Inspect the <strong>Version</strong> column for the Journey you have been editing. You will see a number listed, which represents the latest version number for that Journey.</p></li><li><p>You can also hover over the clock icon, which will display the description associated with the latest Journey version update.</p></li><li><p>Click the <strong>Version History</strong> button to be taken to the complete version history for that Journey.</p></li></ol><h2 id="priority-view" tabindex="-1">Priority View <a class="header-anchor" href="#priority-view" aria-label="Permalink to &quot;Priority View&quot;">​</a></h2><p><strong>Priority View</strong> allows you to set the priority of multiple Journeys when they “overlap,” meaning when a single person is eligible to see multiple Journeys. You can choose the Journey that should show ahead of any others.</p><p>Let&#39;s say you have two Journeys that may reach the same audience:</p><ul><li>A half-page interstitial that promotes an offer on your &quot;Shoes&quot; category page.</li><li>A smart banner that should show for all visitors.</li></ul><p>In general, you&#39;d like the interstitial to show ahead of the smart banner on the &quot;Shoes&quot; category page (where both audience segments overlap). To configure the prioritization:</p><ol><li>In <strong>Filter View</strong>, hover on the priority value of a Journey you want to update.</li><li>In the popover that appears, enter the number and click <strong>Save</strong>.</li><li>The table should refresh with the new priority value(s).</li></ol><p>Alternatively:</p><ol><li>Switch to the <strong>Priority View</strong> by clicking on the toggle.</li><li>Drag and drop Journeys in the order you&#39;d like them to show. Lower numbers mean higher priority (i.e. a Journey with priority 1 is going to show ahead of a Journey with priority 2).</li><li>Click the <strong>Save</strong> button when you&#39;re done.</li></ol><p>Now all Journeys will be prioritized in the order they appear in the table.</p><h3 id="prioritization-faq" tabindex="-1">Prioritization FAQ <a class="header-anchor" href="#prioritization-faq" aria-label="Permalink to &quot;Prioritization FAQ&quot;">​</a></h3><p>Below are a few frequently asked questions about prioritization related to Journeys.</p><h4 id="when-do-my-journeys-prioritization-rules-apply" tabindex="-1">When do my Journeys prioritization rules apply? <a class="header-anchor" href="#when-do-my-journeys-prioritization-rules-apply" aria-label="Permalink to &quot;When do my Journeys prioritization rules apply?&quot;">​</a></h4><p>Prioritization only takes effect when two Journeys are overlapping. If you have a Journey targeting iOS users and a Journey targeting Android users, the prioritization won&#39;t matter. If you update the Journey targeting iOS to now target iOS and Android users, the higher priority Journey will show to Android users.</p><h4 id="what-happens-if-a-user-dismisses-a-banner-or-interstitial" tabindex="-1">What happens if a user dismisses a banner or interstitial? <a class="header-anchor" href="#what-happens-if-a-user-dismisses-a-banner-or-interstitial" aria-label="Permalink to &quot;What happens if a user dismisses a banner or interstitial?&quot;">​</a></h4><p>When a user dismisses a banner or interstitial, that banner or interstitial will be dismissed for the amount of time specified in the Journey’s dismissal settings.</p><p>If the Journey has been configured to dismiss all Journeys when dismissed, no other Journey will be shown to the user for the duration of the dismissal period. However, if the Journey has been configured to dismiss only that Journey, other applicable Journeys will still be shown to the user. To view your dismissal settings, edit your Journey, click Save &amp; Continue, click on the name of your Journey and navigate to Dismissal Settings.</p><h4 id="why-do-i-have-to-prioritize-stopped-and-draft-journeys" tabindex="-1">Why do I have to prioritize stopped and draft Journeys? <a class="header-anchor" href="#why-do-i-have-to-prioritize-stopped-and-draft-journeys" aria-label="Permalink to &quot;Why do I have to prioritize stopped and draft Journeys?&quot;">​</a></h4><p>It’s important to prioritize all non-archived Journeys because Journeys can be set live from draft or stopped mode.</p>',36)])])}const c=t(a,[["render",n]]);export{y as __pageData,c as default};
